import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import {
  DEFAULT_CONTEXT_WINDOW_TOKENS,
  getContextWindowTokens,
  scaleByContextWindow,
  tokensAsContextPct,
} from '../../lib/context-window.js';

describe('context-window', () => {
  const originalEnv = process.env.CLAUDE_MAX_CONTEXT;

  beforeEach(() => {
    delete process.env.CLAUDE_MAX_CONTEXT;
  });

  afterEach(() => {
    if (originalEnv === undefined) {
      delete process.env.CLAUDE_MAX_CONTEXT;
    } else {
      process.env.CLAUDE_MAX_CONTEXT = originalEnv;
    }
  });

  describe('DEFAULT_CONTEXT_WINDOW_TOKENS', () => {
    test('is 1M', () => {
      expect(DEFAULT_CONTEXT_WINDOW_TOKENS).toBe(1_000_000);
    });
  });

  describe('getContextWindowTokens', () => {
    test('returns default when env unset', () => {
      expect(getContextWindowTokens()).toBe(1_000_000);
    });

    test('reads env var when set', () => {
      process.env.CLAUDE_MAX_CONTEXT = '200000';
      expect(getContextWindowTokens()).toBe(200_000);
    });

    test('falls back to default on garbage env value', () => {
      process.env.CLAUDE_MAX_CONTEXT = 'not-a-number';
      expect(getContextWindowTokens()).toBe(1_000_000);
    });

    test('falls back to default on non-positive env value', () => {
      process.env.CLAUDE_MAX_CONTEXT = '0';
      expect(getContextWindowTokens()).toBe(1_000_000);
      process.env.CLAUDE_MAX_CONTEXT = '-500';
      expect(getContextWindowTokens()).toBe(1_000_000);
    });
  });

  describe('scaleByContextWindow', () => {
    test('returns baseline at 1M window', () => {
      expect(scaleByContextWindow(1200)).toBe(1200);
    });

    test('scales down at 200K window', () => {
      process.env.CLAUDE_MAX_CONTEXT = '200000';
      expect(scaleByContextWindow(1200)).toBe(240);
    });

    test('scales up at 2M window', () => {
      process.env.CLAUDE_MAX_CONTEXT = '2000000';
      expect(scaleByContextWindow(1200)).toBe(2400);
    });

    test('rounds to integer', () => {
      process.env.CLAUDE_MAX_CONTEXT = '333333';
      const result = scaleByContextWindow(1000);
      expect(Number.isInteger(result)).toBe(true);
    });
  });

  describe('tokensAsContextPct', () => {
    test('0 tokens → 0%', () => {
      expect(tokensAsContextPct(0)).toBe(0);
    });

    test('100K tokens at 1M window → 10%', () => {
      expect(tokensAsContextPct(100_000)).toBe(10);
    });

    test('clamps to 100% for over-budget', () => {
      expect(tokensAsContextPct(2_000_000)).toBe(100);
    });

    test('respects env window', () => {
      process.env.CLAUDE_MAX_CONTEXT = '200000';
      expect(tokensAsContextPct(100_000)).toBe(50);
    });
  });
});
